int main(void)
{
    /*
     * RCC_APB2ENR
     * -----------
     * Address : 0x40021018
     *
     * RCC (Reset and Clock Control) APB2 Enable Register.
     * This register is used to enable/disable clocks to peripherals
     * connected to the APB2 bus.
     *
     * IOPCEN (Bit 4):
     *      0 -> GPIOC Clock Disabled
     *      1 -> GPIOC Clock Enabled
     *
     * Note:
     * Peripheral registers cannot be accessed unless their
     * corresponding clock is enabled.
     */
    RCC_APB2ENR volatile *const clkptr =
            (RCC_APB2ENR*)0x40021018;

    // Enable the clock for GPIO Port C.
    clkptr->IOPCEN = 1;

    /*
     * GPIOC_CRH
     * ---------
     * Address : 0x40011004
     *
     * GPIO Port Configuration High Register.
     *
     * Responsible for configuring GPIO pins:
     *      PC8 - PC15
     *
     * For PC13:
     *
     * MODE13[1:0]
     *      00 -> Input Mode
     *      01 -> Output (10 MHz)
     *      10 -> Output (2 MHz)
     *      11 -> Output (50 MHz)
     *
     * CNF13[1:0]
     *      00 -> General Purpose Push-Pull
     *      01 -> General Purpose Open-Drain
     *      10 -> Alternate Function Push-Pull
     *      11 -> Alternate Function Open-Drain
     *
     * Configuration:
     *      MODE13 = 10
     *      CNF13  = 00
     *
     * Therefore:
     *      PC13 is configured as a General Purpose
     *      Push-Pull Output running at 2 MHz.
     */
    GPIOx_CRH volatile *const pinconfig_ptr =
            (GPIOx_CRH*)0x40011004;

    pinconfig_ptr->MODE13 = 2;
    pinconfig_ptr->CNF13  = 0;

    /*
     * GPIOC_ODR
     * ---------
     * Address : 0x4001100C
     *
     * GPIO Output Data Register.
     *
     * Bits 15:0 correspond to GPIO pins 15:0.
     *
     * ODR13:
     *      0 -> Drive PC13 LOW
     *      1 -> Drive PC13 HIGH
     *
     * Blue Pill Note:
     * The onboard LED connected to PC13 is Active LOW.
     *
     * Therefore:
     *      PC13 = 0 -> LED ON
     *      PC13 = 1 -> LED OFF
     */
    GPIOx_ODR volatile *const mode_o_i_ptr =
            (GPIOx_ODR*)0x4001100C;

    /*
     * Infinite loop:
     *
     * Blink the onboard LED by repeatedly driving
     * PC13 HIGH and LOW with a software delay.
     */
    while(1)
    {
        // LED OFF (PC13 = HIGH)
        mode_o_i_ptr->ODR13 = 1;

        // Simple software delay.
        for(volatile int d = 0; d < 500000; d++);

        // LED ON (PC13 = LOW)
        mode_o_i_ptr->ODR13 = 0;

        // Simple software delay.
        for(volatile int d = 0; d < 500000; d++);
    }

    /* Loop forever */
	for(;;);
}
